import os
import requests
from joblib import load

def load_latest_model(model_path):
    # Fetch the latest model version from cloud storage
    response = requests.get(os.environ['MODEL_STORAGE_URL'])
    if response.status_code == 200:
        with open('latest_model.joblib', 'wb') as f:
            f.write(response.content)
        
        # Load the model using joblib
        model = load('latest_model.joblib')
        return model
    else:
        raise Exception(f"Failed to fetch model: {response.status_code}")

if __name__ == "__main__":
    model_path = os.environ.get('MODEL_PATH', 'default_model_path')
    try:
        model = load_latest_model(model_path)
        print("Model loaded successfully.")
    except Exception as e:
        print(f"Error loading model: {e}")